<content>import { useCallback, useMemo, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import type { SidebarItemT } from 'Shared/types/SidebarItemT';
import styles from './Sidebar.module.scss';

export type PropsT = {
  items: SidebarItemT[];
  isCollapsed?: boolean;
  onToggle?: () => void;
};

export const Sidebar = (props: PropsT) => {
  const location = useLocation();
  const [isCollapsed, setIsCollapsed] = useState(props.isCollapsed ?? false);

  const handleToggle = useCallback(() => {
    const newState = !isCollapsed;
    setIsCollapsed(newState);
    if (props.onToggle) {
      props.onToggle();
    }
  }, [isCollapsed, props]);

  const itemsWithActiveState = useMemo(() => {
    return props.items.map((item) => ({
      ...item,
      isActive: location.pathname === item.path,
    }));
  }, [props.items, location.pathname]);

  return (
    <aside className={`${styles.sidebar} ${isCollapsed ? styles.collapsed : ''}`}>
      <button className={styles.toggleButton} onClick={handleToggle} aria-label="Toggle sidebar">
        {isCollapsed ? '→' : '←'}
      </button>

      <nav className={styles.navigation}>
        <ul className={styles.list}>
          {itemsWithActiveState.map((item) => (
            <li key={item.id} className={styles.listItem}>
              <Link
                to={item.path}
                className={`${styles.link} ${item.isActive ? styles.active : ''}`}
                aria-current={item.isActive ? 'page' : undefined}
              >
                <span className={styles.icon}>{item.icon}</span>
                {!isCollapsed && <span className={styles.label}>{item.label}</span>}
              </Link>
            </li>
          ))}
        </ul>
      </nav>
    </aside>
  );
};
</content>
</write_file>

