<content>import { Outlet } from 'react-router-dom';
import { useCallback, useMemo, useState } from 'react';
import type { SidebarItemT } from 'Shared/types/SidebarItemT';
import { Sidebar } from './Sidebar';
import styles from './Layout.module.scss';

export const Layout = () => {
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  const sidebarItems = useMemo<SidebarItemT[]>(
    () => [
      {
        id: 'dashboard',
        label: 'Dashboard',
        icon: '📊',
        path: '/',
      },
      {
        id: 'transactions',
        label: 'Transactions',
        icon: '💳',
        path: '/transactions',
      },
      {
        id: 'budgets',
        label: 'Budgets',
        icon: '💰',
        path: '/budgets',
      },
      {
        id: 'reports',
        label: 'Reports',
        icon: '📈',
        path: '/reports',
      },
      {
        id: 'settings',
        label: 'Settings',
        icon: '⚙️',
        path: '/settings',
      },
    ],
    [],
  );

  const handleSidebarToggle = useCallback(() => {
    setIsSidebarCollapsed((prev) => !prev);
  }, []);

  return (
    <div className={styles.layout}>
      <Sidebar items={sidebarItems} isCollapsed={isSidebarCollapsed} onToggle={handleSidebarToggle} />
      <main className={styles.content}>
        <Outlet />
      </main>
    </div>
  );
};
</content>
